PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "events" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "description" text, "location" varchar not null, "latitude" numeric, "longitude" numeric, "start_date" date not null, "end_date" date not null, "booking_start" date not null, "booking_end" date not null, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "hotels" ("id" integer primary key autoincrement not null, "event_id" integer not null, "name" varchar not null, "description" text, "address" varchar not null, "latitude" numeric, "longitude" numeric, "supplier_name" varchar not null, "website_url" varchar, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, "gallery_images" text, foreign key("event_id") references "events"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "room_types" ("id" integer primary key autoincrement not null, "name" varchar not null, "max_guests" integer not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "bookings" ("id" varchar not null, "user_id" integer not null, "event_id" integer not null, "hotel_id" integer not null, "rate_id" integer not null, "check_in" date not null, "check_out" date not null, "guests" integer not null, "nights" integer not null, "subtotal" numeric not null, "fees_total" numeric not null default '0', "total_price" numeric not null, "status" varchar not null default 'PENDING', "cancellation_reason" varchar, "cancelled_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("event_id") references "events"("id") on delete restrict, foreign key("hotel_id") references "hotels"("id") on delete restrict, foreign key("rate_id") references "rates"("id") on delete restrict, primary key ("id"));
CREATE TABLE IF NOT EXISTS "meal_plans" ("id" integer primary key autoincrement not null, "name" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "rates" ("id" integer primary key autoincrement not null, "hotel_id" integer not null, "room_type_id" integer not null, "meal_plan_id" integer not null, "cost_price" numeric not null, "sale_price" numeric not null, "currency" varchar not null default 'EUR', "stock" integer not null, "cancellation_deadline" datetime not null, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("hotel_id") references "hotels"("id") on delete cascade, foreign key("room_type_id") references "room_types"("id") on delete restrict, foreign key("meal_plan_id") references "meal_plans"("id") on delete restrict);
CREATE TABLE IF NOT EXISTS "payments" ("id" integer primary key autoincrement not null, "booking_id" varchar not null, "provider" varchar not null default 'STRIPE_MOCK', "amount" numeric not null, "currency" varchar not null default 'EUR', "status" varchar not null default 'PENDING', "due_date" date not null, "paid_at" datetime, "provider_reference" varchar, "created_at" datetime, "updated_at" datetime, foreign key("booking_id") references "bookings"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "supplier_payments" ("id" integer primary key autoincrement not null, "booking_id" varchar not null, "amount" numeric not null, "currency" varchar not null default 'EUR', "due_date" date not null, "status" varchar not null default 'PENDING', "paid_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("booking_id") references "bookings"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "payment_webhook_events" ("id" integer primary key autoincrement not null, "provider" varchar not null, "event_id" varchar not null, "event_type" varchar not null, "payload" text not null, "processed_at" datetime not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "audit_logs" ("id" integer primary key autoincrement not null, "user_id" integer, "action" varchar not null, "auditable_type" varchar, "auditable_id" varchar, "metadata" text, "ip_address" varchar, "user_agent" text, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "notifications" ("id" varchar not null, "type" varchar not null, "notifiable_type" varchar not null, "notifiable_id" integer not null, "data" text not null, "read_at" datetime, "created_at" datetime, "updated_at" datetime, primary key ("id"));
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "role" varchar not null default ('CLIENT'), "remember_token" varchar, "created_at" datetime, "updated_at" datetime, "hotel_id" integer, foreign key("hotel_id") references "hotels"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "push_subscriptions" ("id" integer primary key autoincrement not null, "user_id" integer not null, "endpoint" text not null, "public_key" varchar not null, "auth_token" varchar not null, "content_encoding" varchar, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
DELETE FROM sqlite_sequence;
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE INDEX "cache_expiration_index" on "cache" ("expiration");
CREATE INDEX "cache_locks_expiration_index" on "cache_locks" ("expiration");
CREATE INDEX "jobs_queue_index" on "jobs" ("queue");
CREATE UNIQUE INDEX "failed_jobs_uuid_unique" on "failed_jobs" ("uuid");
CREATE UNIQUE INDEX "events_slug_unique" on "events" ("slug");
CREATE UNIQUE INDEX "room_types_name_unique" on "room_types" ("name");
CREATE UNIQUE INDEX "meal_plans_name_unique" on "meal_plans" ("name");
CREATE UNIQUE INDEX "rates_unique_combo" on "rates" ("hotel_id", "room_type_id", "meal_plan_id");
CREATE UNIQUE INDEX "payment_webhook_events_provider_event_id_unique" on "payment_webhook_events" ("provider", "event_id");
CREATE INDEX "audit_logs_action_created_at_index" on "audit_logs" ("action", "created_at");
CREATE INDEX "audit_logs_auditable_type_auditable_id_index" on "audit_logs" ("auditable_type", "auditable_id");
CREATE INDEX "notifications_notifiable_type_notifiable_id_index" on "notifications" ("notifiable_type", "notifiable_id");
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE UNIQUE INDEX "push_subscriptions_user_id_endpoint_unique" on "push_subscriptions" ("user_id", "endpoint");
COMMIT;
